import React, { useEffect, useMemo, useState } from 'react';
import { getAdminAnalytics } from '../../services/supabaseAdminService';

const ANALYTICS_REFRESH_MS = 20000;
const ANALYTICS_CACHE_KEY = 'admin_analytics_cache_v1';

const readCachedAnalytics = () => {
    try {
        const raw = localStorage.getItem(ANALYTICS_CACHE_KEY);
        if (!raw) {
            return null;
        }

        const parsed = JSON.parse(raw);
        return parsed && typeof parsed === 'object' ? parsed : null;
    } catch {
        return null;
    }
};

export default function AdminAnalytics() {
    const [stats, setStats] = useState(() => readCachedAnalytics());
    const [loading, setLoading] = useState(() => !readCachedAnalytics());
    const [error, setError] = useState('');

    const load = async ({ silent = false } = {}) => {
        if (!silent) {
            setLoading(true);
            setError('');
        }
        try {
            const nextStats = await getAdminAnalytics();
            setStats(nextStats);
            if (nextStats) {
                localStorage.setItem(ANALYTICS_CACHE_KEY, JSON.stringify(nextStats));
            }
            setError('');
        } catch (err: any) {
            if (!silent) {
                const cached = readCachedAnalytics();
                if (cached) {
                    setStats(cached);
                    setError('');
                } else {
                    setStats(null);
                    setError(err?.message || 'Unable to load analytics data right now.');
                }
            }
        } finally {
            if (!silent) {
                setLoading(false);
            }
        }
    };

    useEffect(() => {
        let cancelled = false;

        if (!stats) {
            load();
        } else {
            window.setTimeout(() => {
                if (!cancelled) {
                    load({ silent: true });
                }
            }, 0);
            setLoading(false);
        }

        const intervalId = window.setInterval(() => {
            if (!cancelled) {
                load({ silent: true });
            }
        }, ANALYTICS_REFRESH_MS);

        return () => {
            cancelled = true;
            window.clearInterval(intervalId);
        };
    }, []);

    const summaryCards = useMemo(() => ([
        {
            label: 'Revenue',
            value: `₱${parseFloat(stats?.total_revenue || 0).toFixed(2)}`,
            accent: 'green',
            note: 'Completed payments only',
        },
        {
            label: 'Orders',
            value: stats?.total_orders || 0,
            accent: 'blue',
            note: 'All tracked orders',
        },
        {
            label: 'Products',
            value: stats?.total_products || 0,
            accent: 'amber',
            note: 'Active catalog items',
        },
        {
            label: 'Users',
            value: stats?.total_users || 0,
            accent: 'slate',
            note: 'Registered accounts',
        },
    ]), [stats]);

    const recentOrders = stats?.recent_orders || [];
    const lowStockProducts = stats?.low_stock_products || [];

    return (
        <div className="admin-page-content admin-analytics-page">
            <div className="analytics-header-row">
                <div>
                    <h2>Analytics</h2>
                    <p>Snapshot your store activity, revenue, and inventory health.</p>
                </div>

                <div style={{ display: 'flex', gap: '0.55rem', alignItems: 'center' }}>
                    <button type="button" className="btn btn-outline btn-sm" onClick={() => load()} disabled={loading}>
                        Refresh
                    </button>
                    <div className="analytics-header-badge">Live stats</div>
                </div>
            </div>

            {error && <div className="alert alert-danger">{error}</div>}

            <section className="analytics-summary-grid">
                {summaryCards.map((card) => (
                    <article className={`analytics-summary-card analytics-summary-card--${card.accent}`} key={card.label}>
                        <span className="summary-accent" />
                        <div>
                            <p>{card.label}</p>
                            <strong>{card.value}</strong>
                            <small>{card.note}</small>
                        </div>
                    </article>
                ))}
            </section>

            <section className="analytics-panel-grid">
                <article className="analytics-panel-card">
                    <div className="analytics-panel-header">
                        <div>
                            <h3>Recent Orders</h3>
                            <p>Latest completed and active transactions.</p>
                        </div>
                    </div>

                    <div className="analytics-list">
                        {recentOrders.length > 0 ? (
                            recentOrders.map((order) => (
                                <div className="analytics-list-row" key={order.id}>
                                    <div>
                                        <strong>{order.order_number || `Order #${order.id}`}</strong>
                                        <p>{order.user?.name || order.user?.email || 'Guest customer'}</p>
                                    </div>
                                    <div className="analytics-list-meta">
                                        <strong>₱{parseFloat(order.total_amount || 0).toFixed(2)}</strong>
                                        <span className={`analytics-status analytics-status--${order.status || 'pending'}`}>
                                            {order.status || 'pending'}
                                        </span>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <p className="analytics-empty">No recent order data yet.</p>
                        )}
                    </div>
                </article>

                <article className="analytics-panel-card">
                    <div className="analytics-panel-header">
                        <div>
                            <h3>Low Stock Alerts</h3>
                            <p>Items that need attention before they run out.</p>
                        </div>
                    </div>

                    <div className="analytics-list">
                        {lowStockProducts.length > 0 ? (
                            lowStockProducts.map((product) => (
                                <div className="analytics-list-row" key={product.id}>
                                    <div>
                                        <strong>{product.name}</strong>
                                        <p>{product.brand || 'Brand not listed'}</p>
                                    </div>
                                    <div className="analytics-list-meta">
                                        <strong>{product.stock ?? 0} left</strong>
                                        <span className="analytics-stock-pill">Low stock</span>
                                    </div>
                                </div>
                            ))
                        ) : (
                            <p className="analytics-empty">No low stock alerts at the moment.</p>
                        )}
                    </div>
                </article>
            </section>
        </div>
    );
}
